import random

def arch_rivals_gameplay_simulation():
    # Simulate a player attempting to steal the ball by punching
    player_action = random.choice(['pass', 'shoot', 'punch'])

    if player_action == 'punch':
        steal_success = random.random() < 0.7  # 70% chance to steal
        if steal_success:
            return 'Opponent was punched and the ball was stolen!'
        else:
            return 'Punch failed, opponent retains possession.'
    elif player_action == 'pass':
        return 'Teammate received the pass.'
    elif player_action == 'shoot':
        shot_success = random.random() < 0.5  # 50% chance to score
        if shot_success:
            return 'Shot made! 2 points scored.'
        else:
            return 'Shot missed, possession lost.'

# Example usage
print(arch_rivals_gameplay_simulation())
